create table if not exists ac_export_logs (id uuid primary key default uuid_generate_v4(), document_type text not null, reference text unique not null, generated_by uuid, reason text not null, region text, payload jsonb default '{}', created_at timestamptz default now());
create table if not exists ac_global_standards (id uuid primary key default uuid_generate_v4(), code text unique, title text, rule text, country_override jsonb default '{}', active boolean default true, created_at timestamptz default now());
create table if not exists ac_country_launch_readiness (id uuid primary key default uuid_generate_v4(), country text, city text, labor_pack_ready boolean default false, trainer_capacity int default 0, certified_pool int default 0, compliance_score int default 0, launch_risk text default 'watch', created_at timestamptz default now());
